function ping(url) {
    return new Promise(resolve => {
        const req = http.get(url, {timeout:2000}, res => { res.resume(); resolve(res.statusCode < 500); });
        req.on('error', () => resolve(false));
        req.on('timeout', () => { req.destroy(); resolve(false); });
    });
}

(async () => {
        const renderers = [];

    if (await ping(SAMSUNG.location)) renderers.push(SAMSUNG);

    const lastPort = flow.get('fiioPort') || 58650;
    const ports = [lastPort];
    for (let d = 1; d <= 50; d++) { ports.push(lastPort + d); ports.push(lastPort - d); }

    const fiioPort = await new Promise(resolve => {
        let done = false;
        let remaining = 0;
        for (const port of ports) {
            if (port < 1 || port > 65535) continue;
            remaining++;
            const descUrl = 'http://' + FIIO_IP + ':' + port + '/dev/' + FIIO_UUID + '/desc.xml';
            ping(descUrl).then(ok => {
                remaining--;
                if (ok && !done) { done = true; resolve(port); }
                else if (remaining === 0 && !done) { resolve(null); }
            });
        }
        if (remaining === 0) resolve(null);
    });

    if (fiioPort !== null) {
        flow.set('fiioPort', fiioPort);
        renderers.push({
            name: 'BubbleUPnP (FiiO M11 Plus)', model: 'BubbleUPnP Media Renderer',
            ip: FIIO_IP,
            avTransportUrl: 'http://' + FIIO_IP + ':' + fiioPort +
                '/dev/' + FIIO_UUID + '/svc/upnp-org/AVTransport/action',
            location: 'http://' + FIIO_IP + ':' + fiioPort + '/dev/' + FIIO_UUID + '/desc.xml'
        });
    }

    renderers.sort((a,b) => a.name.localeCompare(b.name));
    flow.set('renderers', renderers);
    if (!flow.get('selectedRenderer') && renderers.length)
        flow.set('selectedRenderer', renderers[0]);
    node.send({ payload: { renderers } });
})();

